@Override
public float floatValue() {
    if (numerator == null || denominator == null) {
        throw new IllegalArgumentException("Numerator and denominator must not be null");
    }
    if (denominator.equals(BigInteger.ZERO)) {
        throw new ArithmeticException("Denominator cannot be zero");
    }
    BigDecimal numBD = new BigDecimal(numerator);
    BigDecimal denBD = new BigDecimal(denominator);
    BigDecimal resultBD = numBD.divide(denBD, BigDecimal.ROUND_HALF_UP);
    return resultBD.floatValue();
}

@Override
public double doubleValue() {
    if (denominator.equals(BigInteger.ZERO)) {
        throw new ArithmeticException("Division by zero");
    }
    BigInteger[] divideResult = numerator.divideAndRemainder(denominator);
    double result = divideResult[0].doubleValue();
    double remainder = divideResult[1].doubleValue();
    result += remainder / denominator.doubleValue();
    return result;
}

@Override
public double doubleValue() {
    if (numerator == null || denominator == null) {
        throw new IllegalArgumentException("Numerator and denominator must not be null");
    }
    if (denominator.doubleValue() == 0) {
        throw new ArithmeticException("Division by zero");
    }
    return new BigDecimal(numerator.toString()).divide(new BigDecimal(denominator.toString()), BigDecimal.ROUND_HALF_UP).doubleValue();
}

